// ---------- Persistent state ----------
const SAVE_KEY = "loki_mischief_v2";
let state = {
  points:0, mood:"playful",
  careTasks:DEFAULT_CARE_TASKS.map(t=>({text:t,done:false})),
  mischiefTasks:DEFAULT_MISCHIEF_TASKS.map(t=>({text:t,done:false})),
  solvedTricks:{}, relationships:{thor:50, odin:50, heimdall:50, loki:50},
  playedRealms:{}, achievements:{}, questLog:[],
  streak:1, lastActive:null,
  highWaterCare:0, highWaterMisch:0,
  thorWaterAwarded:false, odinMedicineAwarded:false,
  // Loki bond mission (per-day; date stamps so we only credit/penalise once per day)
  lokiBondAwardDate:null, lokiBondAwardedPoints:0, lokiBondAwardedLoki:0,
  lokiBondBurnoutDate:null,
  // Heimdall observatory: daily snapshots of the 10 Care tasks.
  // Shape: { "YYYY-MM-DD": [bool x 10] }. He only watches; never gives points.
  careHistory:{},
  careHistoryLastSeen:null, // ISO date string of the last day we wrote
  // Sigyn's Dungeon: a freely-growing list of transgressions.
  // Each entry: { id, text, punishment, served, ts }
  // Adding an entry deducts 10 points; ticking "served" returns those 10.
  sigynDungeon:[],
};

function load(){
  try{
    const raw=localStorage.getItem(SAVE_KEY);
    if(raw){
      const p=JSON.parse(raw);
      state={...state,...p};
      while(state.careTasks.length<10) state.careTasks.push({text:"",done:false});
      while(state.mischiefTasks.length<10) state.mischiefTasks.push({text:"",done:false});
    }
    // streak logic
    const today=new Date().toDateString();
    if(state.lastActive!==today){
      const yesterday=new Date(Date.now()-86400000).toDateString();
      if(state.lastActive===yesterday) state.streak=(state.streak||0)+1;
      else if(state.lastActive) state.streak=1;
      state.lastActive=today;
    }
  }catch(e){console.warn("Could not load state:",e)}
}
function save(){ try{localStorage.setItem(SAVE_KEY,JSON.stringify(state))}catch(e){} }

// ---------- Heimdall: daily Care snapshot recorder ----------
// He watches everything but rewards nothing.
// On every care-task change AND on init/interval we update today's snapshot
// in state.careHistory. When the calendar day rolls over, the previous day
// is already locked in (we never modify past keys), and today's care checkboxes
// reset to false (so each day starts fresh — same daily rhythm as the rest).
function isoDay(d){
  d = d || new Date();
  const y=d.getFullYear(), m=String(d.getMonth()+1).padStart(2,"0"), dd=String(d.getDate()).padStart(2,"0");
  return y+"-"+m+"-"+dd;
}
function snapshotTodayCare(){
  state.careHistory = state.careHistory || {};
  const today = isoDay();
  state.careHistory[today] = state.careTasks.slice(0,10).map(t=>!!(t&&t.done));
  // keep memory bounded: drop entries older than ~95 days
  const cutoff = new Date(); cutoff.setDate(cutoff.getDate()-95);
  const cutISO = isoDay(cutoff);
  for(const k of Object.keys(state.careHistory)){
    if(k < cutISO) delete state.careHistory[k];
  }
}
function recordCareDay(){
  const today = isoDay();
  const last  = state.careHistoryLastSeen;
  if(last && last !== today){
    // The last day we saw is now in the past. It was already snapshotted live
    // on every check, so no further action is needed to "lock" it.
    // Reset today's care checkboxes — fresh day, fresh page.
    state.careTasks.forEach(t=>{ if(t) t.done=false; });
  }
  // Always (re)write today's snapshot from the current task state.
  snapshotTodayCare();
  state.careHistoryLastSeen = today;
}

