function currentMonthKey(){
  const d=new Date();
  return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0");
}
function currentMonthLabel(){
  const d=new Date();
  return d.toLocaleString(undefined,{month:"long",year:"numeric"});
}

function ensureDeepCleanState(){
  // Auto-reset if month changed.
  const key=currentMonthKey();
  if(!state.deepClean || state.deepClean.month!==key){
    state.deepClean={
      month:key,
      checks:{},   // { areaId: { taskIndex: true } }
      awarded:{},  // { areaId: true } once that area was rewarded this month
    };
  } else {
    state.deepClean.checks = state.deepClean.checks || {};
    state.deepClean.awarded = state.deepClean.awarded || {};
  }
}

function renderTrickster(){
  ensureDeepCleanState();
  const monthLabel=document.getElementById("deepMonthLabel");
  if(monthLabel) monthLabel.textContent="◆ "+currentMonthLabel();

  const grid=document.getElementById("deepGrid");
  if(!grid) return;
  grid.innerHTML="";

  let areasComplete=0;

  DEEP_CLEAN_AREAS.forEach((area)=>{
    const checks=state.deepClean.checks[area.id]||{};
    const total=area.tasks.length;
    const done=area.tasks.reduce((n,_,i)=>n+(checks[i]?1:0),0);
    const pct=total?Math.round((done/total)*100):0;
    const isDone=done===total;
    const wasAwarded=!!state.deepClean.awarded[area.id];
    if(isDone) areasComplete++;

    const card=document.createElement("div");
    card.className="deep-card"+(isDone?" done":"");
    card.innerHTML=`
      <header class="deep-card-head">
        <div class="deep-sigil" aria-hidden="true">${area.icon}</div>
        <div class="deep-card-title">
          <h3>${area.name}</h3>
          <p>${area.blurb}</p>
        </div>
        <span class="deep-badge">${done} / ${total}</span>
      </header>
      <div class="deep-progress" role="progressbar"
           aria-valuemin="0" aria-valuemax="100" aria-valuenow="${pct}"
           aria-label="${area.name} progress">
        <div class="deep-progress-fill" style="width:${pct}%"></div>
      </div>
      ${isDone && wasAwarded ? '<div class="deep-reward-badge">✦ Loki rewarded this area</div>' : ''}
      <ul class="deep-task-list"></ul>
    `;

    const list=card.querySelector(".deep-task-list");
    area.tasks.forEach((task,idx)=>{
      const li=document.createElement("li");
      const cbId="dc_"+area.id+"_"+idx;
      const checked=!!checks[idx];
      li.className="deep-task"+(checked?" checked":"");
      li.innerHTML=`
        <input type="checkbox" id="${cbId}" ${checked?"checked":""} aria-label="${task.replace(/"/g,'&quot;')}">
        <label for="${cbId}">${task}</label>
      `;
      const cb=li.querySelector("input");
      cb.addEventListener("change",()=>{
        state.deepClean.checks[area.id]=state.deepClean.checks[area.id]||{};
        if(cb.checked) state.deepClean.checks[area.id][idx]=true;
        else delete state.deepClean.checks[area.id][idx];
        save();
        // Update THIS row + THIS card in place — do NOT re-render the whole
        // grid, otherwise the scroll position inside every deep-task-list
        // resets and the user gets yanked back to the top.
        li.classList.toggle("checked", cb.checked);
        updateDeepCardStats(area, card);
        checkDeepCleanAreaAward(area,cb);
        updateAll();
      });
      list.appendChild(li);
    });

    grid.appendChild(card);
  });

  const overall=document.getElementById("deepAreasComplete");
  if(overall) overall.textContent=String(areasComplete);
}

// In-place refresh for a single deep-clean card (badge, progress bar, done
// class, reward ribbon) — used when a checkbox toggles, to avoid rerendering
// the entire grid (which would reset every list's scroll position).
function updateDeepCardStats(area, card){
  const checks=state.deepClean.checks[area.id]||{};
  const total=area.tasks.length;
  const done=area.tasks.reduce((n,_,i)=>n+(checks[i]?1:0),0);
  const pct=total?Math.round((done/total)*100):0;
  const isDone=done===total;
  const wasAwarded=!!state.deepClean.awarded[area.id];

  card.classList.toggle("done", isDone);
  const badge=card.querySelector(".deep-badge");
  if(badge) badge.textContent=done+" / "+total;
  const fill=card.querySelector(".deep-progress-fill");
  if(fill) fill.style.width=pct+"%";
  const bar=card.querySelector(".deep-progress");
  if(bar) bar.setAttribute("aria-valuenow", String(pct));

  const existingRibbon=card.querySelector(".deep-reward-badge");
  if(isDone && wasAwarded && !existingRibbon){
    const ribbon=document.createElement("div");
    ribbon.className="deep-reward-badge";
    ribbon.textContent="✦ Loki rewarded this area";
    const list=card.querySelector(".deep-task-list");
    if(list) card.insertBefore(ribbon, list);
  } else if((!isDone || !wasAwarded) && existingRibbon){
    existingRibbon.remove();
  }

  const overall=document.getElementById("deepAreasComplete");
  if(overall){
    const complete=DEEP_CLEAN_AREAS.reduce((n,a)=>{
      const c=state.deepClean.checks[a.id]||{};
      const d=a.tasks.reduce((m,_,i)=>m+(c[i]?1:0),0);
      return n+(d===a.tasks.length?1:0);
    },0);
    overall.textContent=String(complete);
  }
}

function checkDeepCleanAreaAward(area,anchorEl){
  const checks=state.deepClean.checks[area.id]||{};
  const done=area.tasks.every((_,i)=>checks[i]);
  if(done && !state.deepClean.awarded[area.id]){
    state.deepClean.awarded[area.id]=true;
    awardPoints(15,anchorEl);
    state.relationships.loki=Math.min(100,(state.relationships.loki||50)+5);
    addQuest("Deep clean: "+area.name+" — Loki +5, +15 mischief");
    state.mood="smug";
    save();
    // Finale flourish if all four are done this month.
    const allFour=DEEP_CLEAN_AREAS.every(a=>state.deepClean.awarded[a.id]);
    if(allFour) celebrate("DEEP_CLEAN_MONTH","A Realm Polished — "+currentMonthLabel());
  }
}

// ---------- Realms ----------
function renderRealms(){
  const c=document.getElementById("realmGrid"); c.innerHTML="";
  REALMS.forEach((r)=>{
    let isLocked=false;
    let lockLabel="";
    if(r.requiresCompleted && r.requiresCompleted.length){
      const missing=r.requiresCompleted.filter(id=>!state.playedRealms[id]);
      if(missing.length){ isLocked=true; lockLabel="✦ secret"; }
    } else if(r.locked && state.points<(r.unlockAt||0)){
      isLocked=true; lockLabel=`✦ ${r.unlockAt} M`;
    }
    const played=state.playedRealms[r.id];
    const div=document.createElement("div");
    div.className="realm-card"+(isLocked?" locked":"")+(played?" cleared":"");
    let status="✦ Begin";
    if(isLocked) status=lockLabel;
    else if(played) status="✓ Cleared";
    const lockedDesc = r.requiresCompleted
      ? "sealed — finish your morning shower & breakfast first"
      : `sealed — earn ${r.unlockAt} mischief`;
    div.innerHTML=`
      <div class="realm-sigil">${r.icon}</div>
      <div>
        <h3>${r.name}</h3>
        <p class="realm-desc">${isLocked?lockedDesc:r.desc}</p>
      </div>
      <span class="realm-status">${status}</span>`;
    if(!isLocked && (r.scene||r.mission)) div.addEventListener("click",()=>openRealm(r));
    c.appendChild(div);
  });
}
function openRealm(realm){
  if(realm.mission) return openMission(realm);
  const m=document.getElementById("storyModal");
  document.getElementById("storyTitle").textContent=realm.scene.title;
  document.getElementById("storyText").textContent=realm.scene.text;
  const ch=document.getElementById("storyChoices"); ch.innerHTML="";
  realm.scene.choices.forEach((choice)=>{
    const b=document.createElement("button");
    b.textContent=choice.text;
    b.addEventListener("click",()=>{
      awardPoints(choice.points||10,b);
      if(choice.mood) state.mood=choice.mood;
      if(choice.rel){
        for(const k in choice.rel){
          state.relationships[k]=Math.max(0,Math.min(100,(state.relationships[k]||50)+choice.rel[k]));
        }
      }
      state.relationships.loki=Math.max(0,Math.min(100,state.relationships.loki+3));
      state.playedRealms[realm.id]=true;
      addQuest("Walked: "+realm.name);
      document.getElementById("storyText").textContent=choice.reply;
      ch.innerHTML="";
      const close=document.createElement("button"); close.textContent="✦ Close the page";
      close.addEventListener("click",()=>closeStory());
      ch.appendChild(close);
      save(); updateAll();
    });
    ch.appendChild(b);
  });
  m.classList.add("open");
}

// ---------- Multi-step missions (sequential yes/no) ----------
function setStoryLokiVariant(variant){
  const img=document.querySelector("#storyModal .mini-loki img");
  if(img) applySpriteToImg(img, variant);
}
function openMission(realm){
  const m=document.getElementById("storyModal");
  const mission=realm.mission;
  document.getElementById("storyTitle").textContent=mission.title;
  document.getElementById("storyText").textContent=mission.intro;
  const ch=document.getElementById("storyChoices"); ch.innerHTML="";
  setStoryLokiVariant("neutral");
  const begin=document.createElement("button");
  begin.textContent="✦ Begin the mission";
  begin.addEventListener("click",()=>runMissionStep(realm,0));
  ch.appendChild(begin);
  m.classList.add("open");
}
function runMissionStep(realm,idx){
  const mission=realm.mission;
  const step=mission.steps[idx];
  const textEl=document.getElementById("storyText");
  const ch=document.getElementById("storyChoices");
  textEl.textContent=step.prompt;
  ch.innerHTML="";
  const yes=document.createElement("button"); yes.textContent="Yes";
  const no=document.createElement("button"); no.textContent="No";
  yes.addEventListener("click",()=>{
    textEl.textContent=step.yesReply;
    ch.innerHTML="";
    const next=document.createElement("button");
    if(idx+1<mission.steps.length){
      next.textContent="✦ Continue";
      next.addEventListener("click",()=>runMissionStep(realm,idx+1));
    } else {
      // Mission complete!
      next.textContent="✦ Claim your reward";
      next.addEventListener("click",()=>finishMission(realm,next,ch,textEl,false));
    }
    ch.appendChild(next);
  });
  no.addEventListener("click",()=>{
    textEl.textContent=step.noReply;
    if(step.softFail){
      setStoryLokiVariant("happy");
      ch.innerHTML="";
      const cont=document.createElement("button");
      cont.textContent="✦ Continue";
      cont.addEventListener("click",()=>finishMission(realm,cont,ch,textEl,true));
      ch.appendChild(cont);
      return;
    }
    setStoryLokiVariant("angry");
    state.points=Math.max(0,state.points-(mission.failPenalty||10));
    if(mission.failMood) state.mood=mission.failMood;
    state.relationships.loki=Math.max(0,Math.min(100,state.relationships.loki+(mission.failRelLoki||-5)));
    addQuest("Mission failed: "+mission.title);
    ch.innerHTML="";
    const close=document.createElement("button"); close.textContent="✦ Close the page";
    close.addEventListener("click",()=>closeStory());
    ch.appendChild(close);
    save(); updateAll();
  });
  ch.appendChild(yes);
  ch.appendChild(no);
}
function finishMission(realm,btn,ch,textEl,soft){
  const mission=realm.mission;
  const reply = soft && mission.softCompleteReply ? mission.softCompleteReply : mission.completeReply;
  const points = soft && mission.softCompletePoints!=null ? mission.softCompletePoints : (mission.completePoints||25);
  const rel = soft && mission.softCompleteRel ? mission.softCompleteRel : mission.completeRel;
  const mood = soft && mission.softCompleteMood ? mission.softCompleteMood : mission.completeMood;
  const img = soft && mission.softRewardImage!==undefined ? mission.softRewardImage : mission.rewardImage;
  const cap = soft && mission.softRewardCaption ? mission.softRewardCaption : mission.rewardCaption;
  textEl.textContent=reply;
  setStoryLokiVariant("happy");
  awardPoints(points,btn);
  if(mood) state.mood=mood;
  if(rel){
    for(const k in rel){
      state.relationships[k]=Math.max(0,Math.min(100,(state.relationships[k]||50)+rel[k]));
    }
  }
  state.playedRealms[realm.id]=true;
  addQuest("Mission cleared: "+mission.title);
  ch.innerHTML="";
  if(img){
    const card=document.createElement("div");
    card.style.cssText="margin:18px auto;max-width:320px;padding:12px;border:2px solid var(--gold,#d4a857);border-radius:14px;background:linear-gradient(160deg, rgba(40,20,60,.85), rgba(20,40,30,.85));box-shadow:0 0 32px rgba(120,200,140,.35), inset 0 0 20px rgba(212,168,87,.2);text-align:center;animation:cardReveal .8s ease-out;";
    card.innerHTML=`
      <img src="${img}" alt="reward" style="width:100%;border-radius:8px;display:block;" />
      <p style="margin:10px 0 4px;font-family:'Cormorant Garamond',serif;font-size:.95rem;color:var(--gold,#d4a857);letter-spacing:.05em;">${cap||"✦ Reward unlocked ✦"}</p>`;
    ch.appendChild(card);
  }
  const close=document.createElement("button"); close.textContent="✦ Close the page";
  close.addEventListener("click",()=>closeStory());
  ch.appendChild(close);
  save(); updateAll();
}
function closeStory(){document.getElementById("storyModal").classList.remove("open")}

// ---------- Relationships ----------
function bondTier(v){
  if(v>=85) return "Devoted";
  if(v>=65) return "Warm";
  if(v>=40) return "Neutral";
  if(v>=20) return "Wary";
  return "Cold";
}
function renderRelationships(){
  const c=document.getElementById("relGrid"); c.innerHTML="";
  const all=[
    { id:"loki", name:"Loki", role:"the trickster", color:"#2f6b4a", sprite:"loki" },
    ...REL_CHARS,
  ];
  all.forEach((char)=>{
    const val=state.relationships[char.id]??50;
    const div=document.createElement("div");
    div.className="rel-card";
    let extraNote="";
    if(char.id==="thor"){
      const w=getWaterToday();
      if(state.thorWaterAwarded){
        extraNote=`<div class="role" style="color:var(--gold);margin-top:4px;">✦ Hydration mission complete</div>`;
      } else {
        extraNote=`<div class="role" style="margin-top:4px;">💧 ${w.cups}/8 cups today — click to drink</div>`;
      }
      div.setAttribute("data-tip","Open the Water Counter");
    } else if(char.id==="odin"){
      const m=getMedicineToday();
      if(state.odinMedicineAwarded){
        extraNote=`<div class="role" style="color:var(--gold);margin-top:4px;">✦ Remembrance mission complete</div>`;
      } else if(m.total===0){
        extraNote=`<div class="role" style="margin-top:4px;">👁 click to add your medicines</div>`;
      } else {
        extraNote=`<div class="role" style="margin-top:4px;">👁 ${m.takenCount}/${m.total} taken today — click to check off</div>`;
      }
      div.setAttribute("data-tip","Open Odin's Apothecary");
    } else if(char.id==="loki"){
      const today=new Date().toDateString();
      if(state.lokiBondBurnoutDate===today){
        extraNote=`<div class="role" style="color:var(--ember,#c44a2a);margin-top:4px;">⚠ burnout today — pace yourself tomorrow</div>`;
      } else if(state.lokiBondAwardDate===today){
        extraNote=`<div class="role" style="color:var(--gold);margin-top:4px;">✦ Bond honoured today (+${state.lokiBondAwardedPoints||50})</div>`;
      } else {
        extraNote=`<div class="role" style="margin-top:4px;">✦ click to study, make &amp; speak</div>`;
      }
      div.setAttribute("data-tip","Open Bond ✦ Loki");
    } else if(char.id==="heimdall"){
      const days=Object.keys(state.careHistory||{}).length;
      extraNote=`<div class="role" style="margin-top:4px;">🌌 ${days} day${days===1?"":"s"} observed — click for the watchtower</div>`;
      div.setAttribute("data-tip","Open Heimdall's Observatory");
    } else {
      div.setAttribute("data-tip","Speak with "+char.name);
    }
    div.innerHTML=`
      <div class="rel-portrait"><img src="${SPRITE[char.sprite]}" alt="${char.name}" /></div>
      <h3>${char.name}</h3>
      <div class="role">${char.role}</div>
      <div class="rel-meter"><div class="rel-fill" style="width:${val}%; background: linear-gradient(90deg, ${char.color}, var(--gold));"></div></div>
      <div class="rel-bond-tier">${bondTier(val)} ✦ ${val}</div>
      ${extraNote}`;
    div.addEventListener("click",()=>{
      if(char.id==="thor"){ openWaterModal(); return; }
      if(char.id==="odin"){ openMedicinePage(); return; }
      if(char.id==="loki"){ openLokiBondPage(); return; }
      if(char.id==="heimdall"){ openHeimdallPage(); return; }
      openRelScene(char);
    });
    c.appendChild(div);
  });
}

