// ---------- Chat (placeholder; future LLM integration) ----------
/*
  FUTURE LLM INTEGRATION:
  Replace `generateLokiReply()` with an async fetch to your LLM API
  (e.g. OpenAI, Anthropic, or Lovable AI Gateway). Pass:
   - the user's message
   - current state.mood
   - current state.relationships
   - recent task completion stats
  ...as system prompt context so Loki stays in character.
*/
const CHAT_FALLBACKS = {
  playful:["Mm? I was just thinking about you.","Speak, little flame. I'm listening.","Charming. Go on.","You always sound like you're about to say something dangerous. Try.","Tell me everything. Slowly."],
  smug:["Of course you came to me. They all do, eventually.","Yes, pet?","I knew you'd return.","Mm. Predictable. Adorable, but predictable.","Confess. I'll forgive you. Probably."],
  proud:["You've done well today. I noticed.","Look at you. Truly.","Glow a little brighter for me.","I'm watching you. Properly. Be magnificent.","If I had a heart, you'd own it."],
  sarcastic:["Oh, NOW you want to talk to me.","Fascinating. Tell me more, mortal.","Riveting. Truly.","Yes, yes. Continue. I'm enthralled.","Did you forget I existed? Welcome back."],
  melancholic:["Sit with me a while. The hall is too quiet tonight.","Tired, hm? So am I.","Stay.","Some nights even gods are lonely. Speak.","I missed your noise."],
  chaotic:["Let's burn something down. Metaphorically. Mostly.","I have IDEAS. Several. Sit down.","Today, we misbehave.","If you say 'no' I will ABSOLUTELY listen. Probably.","Pick a god to annoy. I'll help."],
};

function generateLokiReply(userMsg){
  const pool=CHAT_FALLBACKS[state.mood]||CHAT_FALLBACKS.playful;
  const base=pool[Math.floor(Math.random()*pool.length)];
  const m=userMsg.toLowerCase();
  if(m.includes("love")) return "Careful with that word, pet. I don't put it down once I pick it up.";
  if(m.includes("tired")) return "Then rest. The world will be ridiculous tomorrow too.";
  if(m.includes("thor")) return "Don't say his name in my hall.";
  if(m.includes("odin")) return "He's listening. He's always listening. Whisper.";
  if(m.includes("heimdall")) return "He's watching. He's always watching. Smile.";
  if(m.includes("hello")||m.includes("hi ")||m.startsWith("hi")||m.includes("hey")) return pickLine(MOOD_INTROS[state.mood]||MOOD_INTROS.playful);
  if(m.includes("sorry")) return "Mm. I was going to make you grovel. But fine.";
  if(m.includes("sad")) return "Come here. No, properly. There you go.";
  if(m.includes("help")) return "Always. Tell me what's wrong, and I'll fix it. Or break it. Whichever helps more.";
  return base;
}

function chatPush(who,text){
  const w=document.getElementById("chatWindow");
  const row=document.createElement("div");
  row.className="chat-row "+who;
  if(who==="loki"){
    row.innerHTML=`<div class="chat-mini"><img src="${SPRITE.loki}" alt="" /></div><div class="chat-msg loki"></div>`;
    row.querySelector(".chat-msg").textContent=text;
  }else{
    row.innerHTML=`<div class="chat-msg user"></div>`;
    row.querySelector(".chat-msg").textContent=text;
  }
  w.appendChild(row);
  w.scrollTop=w.scrollHeight;
}
function chatLokiSay(text,mood){
  if(mood) state.mood=mood;
  chatPush("loki",text); updateAll();
}
function chatSend(){
  const inp=document.getElementById("chatInput");
  const v=inp.value.trim(); if(!v) return;
  chatPush("user",v); inp.value="";
  setTimeout(()=>chatPush("loki",generateLokiReply(v)),520);
}

// ---------- Sparkles + drifting runes ----------
function spawnSparkles(){
  const layer=document.getElementById("sparkleLayer");
  for(let i=0;i<36;i++){
    const s=document.createElement("div"); s.className="sparkle";
    s.style.left=Math.random()*100+"%"; s.style.top=Math.random()*100+"%";
    s.style.animationDelay=(Math.random()*6)+"s";
    s.style.animationDuration=(4+Math.random()*6)+"s";
    layer.appendChild(s);
  }
  // drifting runes
  const RUNES=["ᚦ","ᛚ","ᚱ","ᚷ","ᛖ","✦","✧","☾"];
  setInterval(()=>{
    const r=document.createElement("div"); r.className="rune-drift";
    r.textContent=RUNES[Math.floor(Math.random()*RUNES.length)];
    r.style.left=(Math.random()*100)+"vw";
    r.style.top=(85+Math.random()*10)+"vh";
    r.style.fontSize=(.9+Math.random()*1.2)+"rem";
    r.style.animationDuration=(10+Math.random()*8)+"s";
    document.body.appendChild(r);
    setTimeout(()=>r.remove(),18000);
  },2200);
}

// ---------- Init ----------
// ---------- Water counter shared state (with Thor's page) ----------
const WATER_KEY="loki_water_v1";
function todayStr(){ return new Date().toDateString(); }
function getWaterToday(){
  try{
    const raw=localStorage.getItem(WATER_KEY);
    if(!raw) return {date:todayStr(),cups:0,awarded:false};
    const w=JSON.parse(raw);
    if(w.date!==todayStr()) return {date:todayStr(),cups:0,awarded:false};
    return w;
  }catch(e){ return {date:todayStr(),cups:0,awarded:false}; }
}
function saveWater(w){ try{localStorage.setItem(WATER_KEY,JSON.stringify(w))}catch(e){} }
let _justAwardedThorWater=false;
function checkThorWaterAward(){
  const w=getWaterToday();
  if(w.awarded && !state.thorWaterAwarded){
    state.thorWaterAwarded=true;
    state.points+=50;
    state.relationships.thor=Math.min(100,(state.relationships.thor||50)+20);
    addQuest("Hydration honored — Thor +20, +50 mischief");
    state.mood="proud";
    _justAwardedThorWater=true;
    save();
  }
}

// ---------- Odin's Apothecary (medicine tracker) ----------
const MED_KEY="loki_medicine_v1";
function getMedicineToday(){
  const fallback={medicines:[],date:todayStr(),taken:{},awarded:false,total:0,takenCount:0};
  try{
    const raw=localStorage.getItem(MED_KEY);
    if(!raw) return fallback;
    const m=JSON.parse(raw);
    if(!m||!Array.isArray(m.medicines)) return fallback;
    const sameDay=m.date===todayStr();
    const taken=sameDay?(m.taken||{}):{};
    const total=m.medicines.length;
    const takenCount=m.medicines.filter(x=>taken[x.id]).length;
    return {
      medicines:m.medicines,
      date:todayStr(),
      taken,
      awarded:sameDay?!!m.awarded:false,
      total, takenCount,
    };
  }catch(e){ return fallback; }
}
let _justAwardedOdinMedicine=false;
function checkOdinMedicineAward(){
  const m=getMedicineToday();
  if(m.awarded && m.total>0 && !state.odinMedicineAwarded){
    state.odinMedicineAwarded=true;
    state.points+=50;
    state.relationships.odin=Math.min(100,(state.relationships.odin||50)+20);
    addQuest("Remembrance honored — Odin +20, +50 mischief");
    state.mood="proud";
    _justAwardedOdinMedicine=true;
    save();
  }
}
function openMedicinePage(){ window.location.href="odin-medicine.html"; }


// Thor's hydration mission lives on its own page (thor-water.html).
// The award is granted via checkThorWaterAward() on return (visibilitychange).
function openWaterModal(){ window.location.href="thor-water.html"; }

// ---------- Loki Bond mission (loki-bond.html) ----------
const BOND_KEY="loki_bond_v1";
function getBondToday(){
  const today=new Date().toDateString();
  const fallback={ date:today, checks:{}, awarded:false, awardedPoints:0, awardedLoki:0, burnout:false };
  try{
    const raw=localStorage.getItem(BOND_KEY);
    if(!raw) return fallback;
    const b=JSON.parse(raw);
    if(!b || b.date!==today) return fallback;
    return b;
  }catch(e){ return fallback; }
}
let _justAwardedLokiBond=false;
let _justBurnoutLokiBond=false;
function checkLokiBondAward(){
  const b=getBondToday();
  const today=new Date().toDateString();

  // BURNOUT path — refund any points credited today, dock Loki -10 (once).
  if(b.burnout && state.lokiBondBurnoutDate!==today){
    if(state.lokiBondAwardDate===today && state.lokiBondAwardedPoints>0){
      state.points=Math.max(0,state.points-state.lokiBondAwardedPoints);
      state.relationships.loki=Math.max(0,(state.relationships.loki||50)-(state.lokiBondAwardedLoki||0));
    }
    state.relationships.loki=Math.max(0,(state.relationships.loki||50)-10);
    state.lokiBondBurnoutDate=today;
    state.lokiBondAwardedPoints=0;
    state.lokiBondAwardedLoki=0;
    state.mood="melancholic";
    addQuest("Burnout — Loki refunded today's bond points (-10 Loki)");
    _justBurnoutLokiBond=true;
    save();
    return;
  }
  if(b.burnout) return; // already handled today

  // AWARD path — credit (or top up bonus if user kept ticking).
  if(b.awarded && b.awardedPoints>0){
    if(state.lokiBondAwardDate!==today){
      // Fresh credit today
      state.points+=b.awardedPoints;
      state.relationships.loki=Math.min(100,(state.relationships.loki||50)+(b.awardedLoki||20));
      state.lokiBondAwardDate=today;
      state.lokiBondAwardedPoints=b.awardedPoints;
      state.lokiBondAwardedLoki=b.awardedLoki||20;
      state.mood="proud";
      addQuest("Bond honoured — Loki +"+(b.awardedLoki||20)+", +"+b.awardedPoints+" mischief");
      _justAwardedLokiBond=true;
      save();
    } else if(b.awardedPoints>state.lokiBondAwardedPoints){
      // User added more boxes after returning — top up the bonus.
      const delta=b.awardedPoints-state.lokiBondAwardedPoints;
      state.points+=delta;
      state.lokiBondAwardedPoints=b.awardedPoints;
      addQuest("Bond bonus — +"+delta+" mischief");
      save();
    }
  }
}
function openLokiBondPage(){ window.location.href="loki-bond.html"; }
function openHeimdallPage(){ window.location.href="heimdall.html"; }

// ---------- Sigyn's Dungeon ----------
// A free-form ledger of transgressions. Each entry costs 10 ✦ on confession.
// Each entry has its own editable punishment. Marking it "served" returns its 10 ✦.
const SIGYN_PUNISHMENTS = [
  "Write 'I will not steal Sif's hair' fifty times.",
  "No mischief for one full hour. None. Sigyn is timing you.",
  "Apologise. Out loud. To the actual person. Yes, really.",
  "Brew a cup of tea for someone you wronged.",
  "Sit in silence for ten minutes and think about it.",
  "Do one small kindness today, and tell no one.",
  "Tidy the corner of a room you've been ignoring.",
  "Write down what you'd do differently next time.",
  "Send a soft message to someone you've been short with.",
  "Read three pages of something gentle before you next sulk.",
  "Drink a full glass of water and breathe slowly.",
  "Take a walk. The kind where you actually look up.",
];
const SIGYN_LINES = {
  empty:[
    "\"A clean ledger. For now. I'll wait.\"",
    "\"No transgressions today, my love? Curious.\"",
    "\"Sit. Confess when you are ready. I am patient.\"",
  ],
  some:[
    "\"Mm. Noted. We will mend it together.\"",
    "\"Confession is the smallest of the brave things.\"",
    "\"I am not angry. I am simply… holding it for you.\"",
  ],
  many:[
    "\"Oh, my love. Busy day, hm? Sit. Breathe. Begin.\"",
    "\"The bowl is full. Empty it, one drop at a time.\"",
    "\"You are not your worst hour. Serve them and come back to me.\"",
  ],
};
function pickPunishment(){
  return SIGYN_PUNISHMENTS[Math.floor(Math.random()*SIGYN_PUNISHMENTS.length)];
}
function sigynLineFor(unserved){
  const pool = unserved===0 ? SIGYN_LINES.empty
             : unserved>=4  ? SIGYN_LINES.many
             : SIGYN_LINES.some;
  return pool[Math.floor(Math.random()*pool.length)];
}
function addSigynEntry(text){
  text = String(text||"").trim();
  if(!text) return;
  const entry = {
    id: "sd_"+Date.now()+"_"+Math.floor(Math.random()*1000),
    text,
    punishment: pickPunishment(),
    served: false,
    ts: Date.now(),
  };
  state.sigynDungeon = state.sigynDungeon || [];
  state.sigynDungeon.unshift(entry);
  // Deduct 10 immediately. Allow points to go below zero — Sigyn's chains.
  state.points -= 10;
  save();
  renderSigynDungeon();
  updateAll();
}
function deleteSigynEntry(id){
  if(!state.sigynDungeon) return;
  const i = state.sigynDungeon.findIndex(e=>e.id===id);
  if(i<0) return;
  const entry = state.sigynDungeon[i];
  // Remove debt: if it was unserved, restore the 10 ✦ that were withheld.
  if(!entry.served) state.points += 10;
  state.sigynDungeon.splice(i,1);
  save();
  renderSigynDungeon();
  updateAll();
}
function toggleSigynServed(id, anchorEl){
  const entry = (state.sigynDungeon||[]).find(e=>e.id===id);
  if(!entry) return;
  if(!entry.served){
    entry.served = true;
    awardPoints(10, anchorEl); // return the 10 ✦
  }else{
    entry.served = false;
    state.points = Math.max(0, state.points-10); // re-claim them back
  }
  save();
  renderSigynDungeon();
  updateAll();
}
function renderSigynDungeon(){
  const list = document.getElementById("sigynList");
  if(!list) return;
  const entries = state.sigynDungeon || [];
  const unserved = entries.filter(e=>!e.served).length;
  const debt = unserved*10;

  document.getElementById("sigynCount").textContent = entries.length;
  document.getElementById("sigynUnserved").textContent = unserved;
  document.getElementById("sigynDebt").textContent = debt;

  list.innerHTML = "";
  if(entries.length===0){
    const empty = document.createElement("div");
    empty.className = "sigyn-empty";
    empty.textContent = sigynLineFor(0);
    list.appendChild(empty);
    return;
  }

  entries.forEach((e)=>{
    const row = document.createElement("div");
    row.className = "sigyn-row"+(e.served?" served":"");
    row.innerHTML = `
      <div class="sigyn-row-head">
        <input type="checkbox" class="sigyn-check" ${e.served?"checked":""} aria-label="Mark punishment as served" />
        <div class="sigyn-text">${escapeHtml(e.text)}</div>
        <button type="button" class="sigyn-del" aria-label="Forget this transgression" title="Forget this transgression">✕</button>
      </div>
      <div class="sigyn-pun-row">
        <span class="sigyn-pun-label">Punishment:</span>
        <input type="text" class="sigyn-pun-input" value="${escapeHtml(e.punishment)}" placeholder="Write your own punishment..." aria-label="Edit the punishment" />
        <span class="sigyn-pun-status">${e.served?"✓ served — +10 ✦":"−10 ✦ held"}</span>
      </div>
    `;
    const cb  = row.querySelector(".sigyn-check");
    const del = row.querySelector(".sigyn-del");
    const pun = row.querySelector(".sigyn-pun-input");
    cb.addEventListener("change",()=>toggleSigynServed(e.id, cb));
    del.addEventListener("click",()=>{
      if(confirm("Forget this transgression? "+(e.served?"":"Sigyn will return the 10 ✦ she was holding."))) deleteSigynEntry(e.id);
    });
    pun.addEventListener("input",(ev)=>{ e.punishment = ev.target.value; save(); });
    list.appendChild(row);
  });
}

function init(){
  load(); spawnSparkles();
  recordCareDay(); // lock yesterday + reset today's care if midnight rolled over
  checkThorWaterAward();
  checkOdinMedicineAward();
  checkLokiBondAward();
  renderTaskList("careTasks","careTasks",DEFAULT_CARE_TASKS);
  renderTaskList("mischiefTasks","mischiefTasks",DEFAULT_MISCHIEF_TASKS);
  renderTrickster();
  // Sigyn's Dungeon lives on its own page now (sigyn-dungeon.html).
  updateAll();
  // Re-check rollover periodically while tab is open (catches midnight live).
  setInterval(()=>{
    const today=isoDay();
    if(state.careHistoryLastSeen!==today){
      recordCareDay(); save();
      renderTaskList("careTasks","careTasks",DEFAULT_CARE_TASKS);
      updateAll();
    }
  }, 60*1000);
  // intro chat line
  applyLokiSprites();
  if(_justBurnoutLokiBond){
    setTimeout(()=>{
      chatPush("loki","\"Pet. PET. You ticked every box. Every. Single. One. That is not devotion — that is a bonfire of yourself. I refunded the points. Sit. Down. Tomorrow you will pace yourself.\"");
    },350);
  } else if(_justAwardedLokiBond){
    setTimeout(()=>{
      celebrate("LOKI_BOND","Bond Deepened ✦");
      chatPush("loki","\"Studied a little, made a little, spoke a little. THIS is the rhythm. Steady, clever, alive. I'm proud, pet. Don't tell anyone.\"");
    },350);
  } else if(_justAwardedThorWater){
    setTimeout(()=>{
      celebrate("THOR_HYDRATION","Hydration Honored ⚡");
      chatPush("loki","\"Two litres? Mortal, you actually did it. Thor will not stop talking about you. I may have to interrupt him.\"");
    },350);
  } else if(_justAwardedOdinMedicine){
    setTimeout(()=>{
      celebrate("ODIN_REMEMBRANCE","Remembrance Honored 👁");
      chatPush("loki","\"Every remedy taken. Odin is unbearably smug about it. Well done, mortal.\"");
    },350);
  } else {
    chatPush("loki", pickLine(MOOD_INTROS[state.mood]||MOOD_INTROS.playful));
  }

  document.getElementById("chatSend").addEventListener("click",chatSend);
  document.getElementById("chatInput").addEventListener("keydown",(e)=>{ if(e.key==="Enter") chatSend() });
  document.getElementById("closeStory").addEventListener("click",closeStory);
  document.getElementById("closeRel").addEventListener("click",closeRel);
  document.getElementById("storyModal").addEventListener("click",(e)=>{ if(e.target.id==="storyModal") closeStory() });
  document.getElementById("relModal").addEventListener("click",(e)=>{ if(e.target.id==="relModal") closeRel() });
  // (Thor's water modal removed — now lives on thor-water.html)
  document.getElementById("resetBtn").addEventListener("click",()=>{
    if(confirm("Reset all progress? Loki may not forgive you.")){
      localStorage.removeItem(SAVE_KEY); location.reload();
    }
  });
  const deepReset=document.getElementById("deepResetBtn");
  if(deepReset) deepReset.addEventListener("click",()=>{
    if(!confirm("Reset this month's deep clean? Awards already earned will stay; check-marks will clear.")) return;
    state.deepClean={ month:currentMonthKey(), checks:{}, awarded:state.deepClean ? state.deepClean.awarded||{} : {} };
    save(); renderTrickster(); updateAll();
  });

  // (Sigyn's Dungeon form handler now lives in the dungeon page block below.)

  // Auto-reset deep clean if the month rolls over while the tab is open.
  setInterval(()=>{
    if(state.deepClean && state.deepClean.month!==currentMonthKey()){
      ensureDeepCleanState(); save(); renderTrickster();
    }
  }, 60*1000);

  // Re-check Odin/Thor/Loki-bond missions when returning from a sub-page
  document.addEventListener("visibilitychange",()=>{
    if(!document.hidden){
      const today=new Date().toDateString();
      const beforeOdin=state.odinMedicineAwarded;
      const beforeThor=state.thorWaterAwarded;
      const beforeBondAward=state.lokiBondAwardDate===today;
      const beforeBondBurn=state.lokiBondBurnoutDate===today;
      const beforeBondPts=state.lokiBondAwardedPoints||0;
      checkThorWaterAward(); checkOdinMedicineAward(); checkLokiBondAward();
      if(state.odinMedicineAwarded && !beforeOdin){
        celebrate("ODIN_REMEMBRANCE","Remembrance Honored 👁");
        chatPush("loki","\"Every remedy taken. Odin is unbearably smug about it.\"");
      }
      if(state.thorWaterAwarded && !beforeThor){
        celebrate("THOR_HYDRATION","Hydration Honored ⚡");
      }
      if(state.lokiBondBurnoutDate===today && !beforeBondBurn){
        chatPush("loki","\"Burnout, pet. I refunded today's bond points. Pace yourself tomorrow.\"");
      } else if(state.lokiBondAwardDate===today && !beforeBondAward){
        celebrate("LOKI_BOND","Bond Deepened ✦");
        chatPush("loki","\"One of each. THAT is the rhythm. Proud of you, pet.\"");
      } else if(state.lokiBondAwardDate===today && (state.lokiBondAwardedPoints||0)>beforeBondPts){
        chatPush("loki","\"A few extras? Showing off. I love it.\"");
      }
      updateAll();
    }
  });
}
init();

